from langflow.custom import CustomComponent


class LotEqpRulebasedQuery(CustomComponent):
    display_name = "Lot/Eqp Rule-based Classifier"
    description = "LLM 없이 regex 로 lot_id/eqp_id 구분 후 API 직접 호출"

    def build_config(self):
        return {
            "input_text": {
                "display_name": "Input Text",
                "input_types": ["Message"],
            }
        }

    def build(self, input_text: str) -> str:
        import re
        import json
        import requests

        text = str(input_text).strip()

        # ── API 설정 (실제 사내 API 로 교체하세요) ──────────────────────
        LOT_API = "http://YOUR-MES-API/api/lot/{lot_id}"
        EQP_API = "http://YOUR-MES-API/api/eqp/{eqp_id}"
        HEADERS = {
            "Authorization": "Bearer YOUR-API-TOKEN",
            "Content-Type": "application/json",
        }
        TIMEOUT = 5
        # ───────────────────────────────────────────────────────────────

        def call(url):
            try:
                resp = requests.get(url, headers=HEADERS, timeout=TIMEOUT)
                resp.raise_for_status()
                return json.dumps(resp.json(), ensure_ascii=False, indent=2)
            except requests.exceptions.Timeout:
                return "API 응답 시간 초과"
            except requests.exceptions.ConnectionError:
                return "API 서버에 연결할 수 없습니다"
            except requests.exceptions.HTTPError as e:
                return f"HTTP {e.response.status_code}"
            except Exception as e:
                return f"오류: {str(e)}"

        # Rule 1: eqp_id - '호기' 접미사 패턴 (예: CMPS04호기)
        eqp_match = re.search(r'([A-Z][A-Z0-9]*\d+호기)', text, re.UNICODE)
        if eqp_match:
            eqp_id = eqp_match.group(1)
            url = EQP_API.replace("{eqp_id}", eqp_id)
            return f"[Equipment ID: {eqp_id}]\n{call(url)}"

        # Rule 2: lot_id - 한글 제거 후 영문+숫자 혼합 5~10자 (예: 5QQ5847)
        clean = re.sub(r'[가-힣\s]+', ' ', text).upper().strip()
        for candidate in re.findall(r'\b([A-Z0-9]{5,10})\b', clean):
            if re.search(r'[A-Z]', candidate) and re.search(r'[0-9]', candidate):
                url = LOT_API.replace("{lot_id}", candidate)
                return f"[Lot ID: {candidate}]\n{call(url)}"

        return (
            "⚠️ Lot ID 또는 Equipment ID 를 인식할 수 없습니다.\n\n"
            "입력 예시:\n"
            "  · Lot : 5QQ5847 이 지금 어느 step 에 있지?\n"
            "  · Eqp : CMPS04호기가 지금 다운 상태인가?"
        )
